root.js-content:
stp.writeLog("Start do stp JS");
stp.setAutoProcess(true);
stp.setUserId("CSBANK");
var sTxId = stp.getXslMsgTagVal("Document/BaselnReSubmissn/TxId","Id");
var arrKeys = [["TSU_TID",sTxId]];
var arrGetDataResult = stp.SYS_getCUBKVal("GetMainRefByTxId",arrKeys);
var sMainRef = arrGetDataResult[0];
var sTrxRole = arrGetDataResult[1];
stp.updateFieldValue("TSU_TRX_ROLE",sTrxRole);
stp.setMainRef(sMainRef);
stp.updateFieldValue("PARENT_MAIN_REF",sTxId);
stp.updateFieldValue("CURRNT_STATUS","Uploaded Resubmitted Purchase Order");
stp.writeLog("End do stp JS");
